type MyData struct {
	Name string `json:"name"`
	Age  int    `json:"age"`
}

// Handler function that parses, validates, and responds with JSON
func myHandler(w http.ResponseWriter, r *http.Request) {
	// Only allow POST requests
	if r.Method != http.MethodPost {
